def seed_translations() -> int:
    """Seed claim translations and return the number of rows upserted."""
    conn = psycopg2.connect(DATABASE_URL)
    cursor = conn.cursor()

    rows_to_upsert = []
    total_keys = 0

    for lang, keys_dict in TRANSLATIONS.items():
        for key, value in keys_dict.items():
            full_key = f"claim.{key}"
            rows_to_upsert.append((lang, full_key, value))
        print(f"Seeded {lang}: {len(keys_dict)} keys")
        total_keys += len(keys_dict)

    execute_values(
        cursor,
        """
        INSERT INTO translations (lang, key, value)
        VALUES %s
        ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value
        """,
        rows_to_upsert,
        template="(%s, %s, %s)",
    )

    conn.commit()
    cursor.close()
    conn.close()

    return len(rows_to_upsert)


if __name__ == "__main__":
    count = seed_translations()
    print(f"✅ Done: {count} translations inserted/updated")
